// client/src/pages/AboutUsPage.jsx
import React from 'react';
import './StaticPage.css';

const AboutUsPage = () => {
    return (
        <div className="static-page container">
            <h1>About My Electroo</h1>
            <div className="static-content card">
                <p>Welcome to My Electroo, your premier destination for high-quality electronics! our mission is to provide cutting-edge technology and exceptional customer service to tech enthusiasts and everyday users alike.</p>
                <p>We believe in the power of innovation and strive to bring you the latest gadgets, home appliances, computing solutions, and audio equipment from leading brands around the world. Our carefully curated selection ensures that you find products that not only meet your needs but also exceed your expectations.</p>
                <p>At My Electroo, we are more than just an online store. We are a community of passionate individuals dedicated to helping you make informed decisions. Our team is committed to providing detailed product information, helpful guides, and responsive support to ensure a seamless shopping experience.</p>
                <p>Thank you for choosing My Electroo. We look forward to serving you and becoming your trusted partner in all things electronics!</p>
            </div>
        </div>
    );
};

export default AboutUsPage;
